#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, N;
        if (scanf("%d %d", &X, &N) != 2) break;
        printf("%d\n", X - N);
    }
    return 0;
}

